#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int tracking[3];
    scanf("%d %d %d", &tracking[0], &tracking[1], &tracking[2]);
    qsort(tracking, 3, sizeof(int), compare);
    int x = tracking[0], y = tracking[1], z = tracking[2];
    int result;
    if (x * 2 >= y && y * 2 >= z) {
        result = x + y + z;
    } else {
        result = (tracking[0] + tracking[1]) * 2;
    }
    printf("%d\n", result);
    return 0;
}
